"""CLI bridge for ortho context add/search."""

import json
import sys
from pathlib import Path
from typing import Optional

# Spawned as a bare script by the TS CLI — add dependencies to path FIRST
_PROJECT_ROOT = Path(__file__).resolve().parents[4]
for _p in (
    _PROJECT_ROOT / "shared" / "storage" / "src",
    _PROJECT_ROOT / "packages" / "context-hub" / "src",
    _PROJECT_ROOT / "packages" / "repo-intelligence" / "src",
):
    if str(_p) not in sys.path:
        sys.path.insert(0, str(_p))


def _import_deps():
    """Lazy import after sys.path is set."""
    global ArtifactStore, ArtifactIngestionRequest, BM25Search, OrthoDatabase
    from context_hub.store import ArtifactStore
    from context_hub.ingestion import ArtifactIngestionRequest
    from context_hub.search.bm25 import BM25Search
    # storage.py is in shared/storage/src/, import directly
    import storage
    OrthoDatabase = storage.OrthoDatabase


class ContextCommand:
    """Thin argparse bridge over ArtifactStore + search."""

    def __init__(self, repo_root: Path):
        self.repo_root = Path(repo_root)

    def add(
        self,
        title: str,
        content: str,
        artifact_type: str = "dev_note",
        source: str = "manual",
        tags: Optional[str] = None,
    ) -> dict:
        """Add an artifact to the store.

        Returns:
            {"artifact_id": "...", "version": 1}
        """
        _import_deps()
        tag_list = [t.strip() for t in (tags or "").split(",")] if tags else []

        db = OrthoDatabase(self.repo_root)
        db.migrate()
        store = ArtifactStore(db, repo_id="repo")

        req = ArtifactIngestionRequest(
            type=artifact_type,
            title=title,
            content=content,
            source=source,
            relevance_scope="global",
            tags=tag_list,
        )
        artifact_id = store.ingest_artifact(req)
        artifact = store.get_artifact(artifact_id)

        return {"artifact_id": artifact_id, "version": artifact.version if artifact else 1}

    def search(
        self,
        query: str,
        limit: int = 10,
        artifact_type: Optional[str] = None,
    ) -> dict:
        """Search for artifacts.

        Returns:
            {"results": [{"artifact_id": "...", "title": "...", ...}]}
        """
        _import_deps()
        db = OrthoDatabase(self.repo_root)
        db.migrate()
        store = ArtifactStore(db, repo_id="repo")

        # BM25 only (HybridSearch degrades to BM25 with NullEmbedding; identical result)
        conn = db.connection()
        search = BM25Search(conn)
        results = search.search(
            query,
            limit=limit,
            type_filter=[artifact_type] if artifact_type else None,
        )
        conn.close()

        return {
            "results": [
                {
                    "artifact_id": r.artifact_id,
                    "title": r.title,
                    "type": r.type,
                    "relevance_score": r.relevance_score,
                    "source": r.source,
                }
                for r in results
            ]
        }


def _main() -> None:
    """CLI entry point for ortho context add|search."""
    import argparse
    import sys

    parser = argparse.ArgumentParser(description="ortho context")
    parser.add_argument("--repo-root", default=".", help="Repository root path")

    subparsers = parser.add_subparsers(dest="action", required=True)

    add_parser = subparsers.add_parser("add", help="Add artifact to context")
    add_parser.add_argument("--title", required=True, help="Artifact title")
    add_parser.add_argument("--content", required=True, help="Artifact content")
    add_parser.add_argument(
        "--type", dest="artifact_type", default="dev_note",
        help="Artifact type: adr, architecture, benchmark, decision, dev_note (default), frd, spec, etc."
    )
    add_parser.add_argument(
        "--source", default="manual", help="Artifact source (default: manual)"
    )
    add_parser.add_argument("--tags", help="Comma-separated tags")

    search_parser = subparsers.add_parser("search", help="Search context")
    search_parser.add_argument("query", help="Search query")
    search_parser.add_argument("--limit", type=int, default=10, help="Result limit")
    search_parser.add_argument("--type", dest="artifact_type", help="Filter by type")
    search_parser.add_argument("--format", default="json", choices=["json", "text"], help="Output format (default: json)")

    args = parser.parse_args()
    cmd = ContextCommand(Path(args.repo_root))

    try:
        if args.action == "add":
            result = cmd.add(
                title=args.title,
                content=args.content,
                artifact_type=args.artifact_type,
                source=args.source,
                tags=args.tags,
            )
        elif args.action == "search":
            result = cmd.search(
                query=args.query,
                limit=args.limit,
                artifact_type=args.artifact_type,
            )
        else:
            sys.exit(1)

        print(json.dumps(result))
        sys.exit(0)
    except Exception as e:
        print(json.dumps({"error": str(e)}), file=sys.stderr)
        sys.exit(1)


if __name__ == "__main__":
    _main()
